// Кладём фото в binary — так его можно передать в vision-модель как изображение.
const row = $input.item.json;
const buf = Buffer.from(row.file_b64, 'base64');
const isPng = buf[0] === 0x89 && buf[1] === 0x50;
const binary = await this.helpers.prepareBinaryData(buf, isPng ? 'evidence.png' : 'evidence.jpg', isPng ? 'image/png' : 'image/jpeg');
return [{ json: { file_id: row.file_id }, binary: { data: binary } }];

// Причёсываем сырые описания по фото в одну сводку для мейн-агента.
const items = $input.all();
if (!items.length) {
  return [{ json: { summary: 'Фото по этому кейсу не найдено.', perPhoto: [] } }];
}
const perPhoto = items.map(it => ({
  file_id: it.json.file_id,
  description: String(it.json.text || it.json.output || '').trim()
}));
const summary = perPhoto.map((p, i) => `Фото ${i + 1}: ${p.description}`).join('\n');
return [{ json: { summary, perPhoto } }];
